+                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
+                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                    </div>
+                                    <div class="d-flex gap-1">
+                                        @if (GetColumnIndex(column) > 0)
+                                        {
+                                            <button class="btn btn-outline-secondary btn-sm" @onclick="() => MoveTask(task.Id, _columns[GetColumnIndex(column) - 1])" disabled="@_processing">
+                                                &larr; Move Left
+                                            </button>
+                                        }
+                                        @if (GetColumnIndex(column) < _columns.Length - 1)
+                                        {
+                                            <button class="btn btn-outline-secondary btn-sm" @onclick="() => MoveTask(task.Id, _columns[GetColumnIndex(column) + 1])" disabled="@_processing">
+                                                Move Right &rarr;
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (_showFormForColumn == column)
+                        {
+                            <div class="card border-primary mb-2">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Title" @bind="_newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee" @bind="_newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-1" @bind="_newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-primary btn-sm" @onclick="() => SaveTask(column)" disabled="@_processing">Save</button>
+                                        <button class="btn btn-secondary btn-sm" @onclick="CancelAdd" disabled="@_processing">Cancel</button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer">
+                        <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => ShowAddForm(column)" disabled="@(_showFormForColumn is not null)">
+                            + Add Task
+                        </button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
+    private List<TaskItem> _allTasks = new();
+    private bool _loading = true;
+    private bool _processing;
+    private string? _errorMessage;
+    private string _searchText = string.Empty;
+
+    // Add-task form state
+    private string? _showFormForColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+
+    private int OverdueCount => _allTasks.Count(t => t.DueDate.Date < DateTime.Today && t.Status != "Done");
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumnTasks(string status) =>
+        _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status) =>
+        _allTasks
+            .Where(t => t.Status == status)
+            .Where(t => string.IsNullOrWhiteSpace(_searchText) || t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase))
+            .ToList();
+
+    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTask(int taskId, string newStatus)
+    {
+        _processing = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var idx = _allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                var old = _allTasks[idx];
+                _allTasks[idx] = old with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            _processing = false;
+        }
+    }
+
+    private void ShowAddForm(string column)
+    {
+        _showFormForColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => _showFormForColumn = null;
+
+    private async Task SaveTask(string column)
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+            return;
+
+        _processing = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
+            // CreateTaskAsync may not set the status to the target column, so ensure it matches
+            _allTasks.Add(created.Status == column ? created : created with { Status = column });
+            _showFormForColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            _processing = false;
+        }
+    }
+}
+

